async function main() {
  console.log('Clearing old data...')
  await prisma.tool.deleteMany({})
  await prisma.article.deleteMany({})

  console.log('Seeding Tools...')
  for (const t of allTools) {
    const slug = t.name.toLowerCase().replace(/\s+/g, '-') + '-' + Math.random().toString(36).substring(2, 6);
    await prisma.tool.create({
      data: {
        name: t.name,
        slug: slug,
        description: t.long || t.desc,
        shortDesc: t.desc,
        url: t.url,
        pricing: t.pricing.toLowerCase(),
        emoji: t.icon,
        rating: t.rating,
        category: t.cat,
        tags: JSON.stringify(t.tags || []),
        features: JSON.stringify(t.plans || []), // using plans as features for now since feature array is empty
        pros: JSON.stringify(t.pros || []),
        cons: JSON.stringify(t.cons || []),
      }
    })
  }

  console.log('Seeding News...')
  for (const n of newsData) {
    const slug = n.title.toLowerCase().replace(/[^a-z0-9]+/g, '-') + '-' + Math.random().toString(36).substring(2, 6);
    await prisma.article.create({
      data: {
        title: n.title,
        slug: slug,
        content: n.body || n.summary,
        summary: n.summary,
        source: n.source,
        author: n.author,
        readTime: n.readTime,
        category: n.cat,
        emoji: n.emoji,
        tags: JSON.stringify(n.tags || []),
        featured: n.featured,
      }
    })
  }
}

main()
  .catch(e => {
    console.error(e)
    process.exit(1)
  })
  .finally(async () => {
    await prisma.$disconnect()
    console.log('Done.')
  })
